import { Injectable, signal, computed } from '@angular/core';

export type Tab = 'readings' | 'tank' | 'motor' | 'ratio' | 'guide' | 'analyser';

export interface NpkData {
  n: number;
  p: number;
  k: number;
  timestamp: Date | null;
}

export interface TankData {
  methane: number; // Raw Analog Value (approx ppm)
  temperature: number; // Celsius
  humidity: number; // %
  ph: number;
}

export interface SoilType {
  id: string;
  name: string;
  characteristics: string;
  profile: Record<string, number>;
  profileText: string;
  crops: string;
}

export interface Fertilizer {
  name: string;
  n: number;
  p: number;
  k: number;
  description: string;
}

export interface Crop {
  name: string;
  // Absolute values for Ratio Calculator
  idealN: number; 
  idealP: number;
  idealK: number;
  // Rich content for Guide
  macro: string;
  micro: string;
  needs: Record<string, number>; // 1-3 scale for chart
}

export interface OrganicAdditive {
  id: string;
  name: string;
  boosts: string;
  description: string;
  nutrientBoost: Record<string, number>;
}

@Injectable({
  providedIn: 'root'
})
export class DataService {
